import{_ as a,c as i,a as t,o as s}from"./app-CEcM0piI.js";const n={};function r(l,e){return s(),i("div",null,e[0]||(e[0]=[t('<h3 id="缓存穿透" tabindex="-1"><a class="header-anchor" href="#缓存穿透"><span>缓存穿透</span></a></h3><p>缓存穿透是指客户端请求的数据在缓存中和数据库中都不存在，这样缓存永远不会生效，这些请求都会打到数据库。</p><p>常见的解决方案有两种：</p><ol><li>缓存空对象:如果查询到缓存和数据库中都没有这条数据就在缓存中缓存一个null并返回,这样下次请求该数据的话就不用频繁查询数据库了.会带来额外的内存消耗</li><li>布隆过滤:当数据进行请求时先查询布隆过滤器,如果布隆过滤器中记录的请求数据存在的话再向缓存请求,否则就返回空.布隆过滤器就是一个哈希表,内存占用少,实现起来复杂,也存在误判的可能</li></ol><h3 id="缓存雪崩" tabindex="-1"><a class="header-anchor" href="#缓存雪崩"><span>缓存雪崩</span></a></h3><p>缓存雪崩是指在同一时段大量的缓存key同时失效或者Redis服务岩机，导致大量请求到达数据库，带来巨大压力。 解决方案:</p><ol><li>对于多个缓存同时失效的原因,可以给不同key的TTL添加随机值</li><li>对于redis宕机,可以利用redis集群提高服务的高可用性</li><li>当redis出现故障时,可以做服务降级,拒绝服务</li><li>给业务添加多级缓存</li></ol><h3 id="缓存击穿" tabindex="-1"><a class="header-anchor" href="#缓存击穿"><span>缓存击穿</span></a></h3><p>缓存击穿问题也叫热点Key问题，就是一个被高并发访问并且缓存重建业务较复杂的key突然失效了，无数的请求访问会在瞬间给数据库带来巨大的冲击。</p>',9)]))}const p=a(n,[["render",r]]),d=JSON.parse('{"path":"/tools/redis/3/","title":"3 缓存问题","lang":"zh-CN","frontmatter":{"title":"3 缓存问题","createTime":"2025/04/05 12:12:26","permalink":"/tools/redis/3/"},"readingTime":{"minutes":1.43,"words":428},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/工具/Redis/3 缓存问题.md","headers":[]}');export{p as comp,d as data};
